- "rock artists": Musicians or bands that play rock music;
- "more than a single album": Refers to artists who have released more than one album;
- "album titles": The names of the albums released by the artists.

sql:
SELECT title
FROM albums
WHERE release_date = (SELECT MIN(release_date) FROM albums);

SELECT name
FROM artists
WHERE artist_id NOT IN (
  SELECT artist_id FROM album_artists
);

